import java.util.Scanner;

public class SecureBufferOverflow {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Limiting the input size to prevent buffer overflow
        if (name.length() > 10) {
            System.out.println("Input size exceeds limit. Please enter a name with at most 10 characters.");
            return;
        }

        // Using StringBuilder to store user input dynamically
        StringBuilder buffer = new StringBuilder();
        buffer.append(name);

        System.out.println("Hello, " + buffer.toString());
    }
}

### Explanation:
취약유형: Buffer Overflow
